// 1. Access Data
const body = $json.body || $json;
const binary = $binary || {};

// 2. Auto-detect if a file was uploaded (handles 'data', 'data0', or any other key)
const binaryKeys = Object.keys(binary);
const firstFileKey = binaryKeys.length > 0 ? binaryKeys[0] : null;

const hasFile = !!firstFileKey;
const hasText = body.book_name;

if (hasText && hasFile) {
  throw new Error("Invalid request: choose file OR book_name, not both");
}

// 3. Handle File Upload
if (hasFile) {
  const file = binary[firstFileKey];
  const ext = (file.fileExtension || "").toLowerCase();

  if (!["pdf"].includes(ext)) {
    throw new Error(`Unsupported file type: ${ext}`);
  }

  // We return the binary object under the key 'data' explicitly
  // This ensures the next node always finds it as 'data', regardless of input name
  return [{
    json: {
      inputType: "file",
      fileName: file.fileName,
      fileType: ext,
      mimeType: file.mimeType,
      fileSize: file.fileSize,
      receivedAt: new Date().toISOString()
    },
    binary: {
      data: file
    }
  }];
}

// 4. Handle Text Input
// 4. Handle Text Input
if (hasText) {
  let name = body.book_name;
  if (typeof name !== 'string') name = String(name);
  name = name.trim();

  if (name.length < 3) {
    throw new Error("book_name is too short");
  }

  const normalizedTitle = name
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, "")  // keep letters, numbers, spaces
    .trim()
    .replace(/\s+/g, "_");        // replace spaces with underscores

  return [{
    json: {
      inputType: "text",
      originalTitle: name,
      normalizedTitle,   // updated safe version
      receivedAt: new Date().toISOString()
    }
  }];
}

throw new Error("Invalid request: provide book_name OR upload file");

const bookText = $json.cleanedText;

if (!bookText || typeof bookText !== 'string') {
  throw new Error('bookText missing or invalid');
}

const CHARS_PER_TOKEN = 3.5;
const MAX_TOKENS = 240000;

const approxTokens = Math.ceil(bookText.length / CHARS_PER_TOKEN);

return [{
  json: {
    bookLength: bookText.length,
    approxTokens,
    exceedsLimit: approxTokens > MAX_TOKENS,
    recommendedChunks: Math.ceil(approxTokens / MAX_TOKENS),
    wordCount: bookText.split(/\s+/).length
  }
}];

const book = $input.first().json;
const formats = book.formats || {};

// Super reliable order for text extraction
const priority = [
  'text/plain; charset=us-ascii',       // Pure text, best
  'text/plain',                         // Sometimes without charset
  'text/html',                          // HTML → easy strip
  'application/pdf',                    // Rare, last resort
  'application/epub+zip'                // Only if desperate
];

let bestFormat = null;
let bestUrl = null;

for (const key of priority) {
  if (formats[key]) {
    bestFormat = key;
    bestUrl = formats[key];
    break;
  }
}

if (!bestUrl) {
  throw new Error(`No usable text format found for "${book.title}"`);
}

return [{
  json: {
    title: book.title,
    id: book.id,
    authors: book.authors?.map(a => a.name).join(', ') || 'Unknown',
    downloadUrl: bestUrl,
    format: bestFormat,
    note: `Selected: ${bestFormat} (plain text preferred for easy extraction)`
  }
}];

const items = $input.all();
const cloudName = "drdujsp3a";

const sceneIds = items
  .map(item => item.json.public_id)
  .filter(id => id && id.startsWith('scene_'));

if (sceneIds.length === 0) {
  throw new Error("No scene public_ids found for concatenation");
}

// First scene is the base
const baseScene = sceneIds[0];

// Build splice chain for remaining scenes only
let spliceChain = '';
sceneIds.slice(1).forEach(id => {
  const escapedId = id.replace(/\//g, ':');
  spliceChain += `fl_splice,l_video:${escapedId},fl_layer_apply/`;
});

const finalUrl = `https://res.cloudinary.com/${cloudName}/video/upload/` +
                 spliceChain +
                 `f_mp4,fl_force_strip/${baseScene}.mp4`;

return [{
  json: {
    final_video_url: finalUrl,
    scene_count: sceneIds.length,
    debug_ids: sceneIds
  }
}];

// Get inputs
const body = $json.body || {};
const binary = $input.first().binary || {};

// Helper to get the file data regardless of the key name (data, data0, file)
const binaryKeys = Object.keys(binary);
const fileKey = binaryKeys.length > 0 ? binaryKeys[0] : null;

if (!fileKey) {
  throw new Error('Missing file upload');
}

if (!body.title || typeof body.title !== 'string') {
  throw new Error('Missing or invalid title');
}

const title = body.title.trim();
const normalized_title = title.toLowerCase()
  .replace(/[^a-z0-9\s]/g,"")
  .trim()
  .replace(/\s+/g, "_");

return [{
  json: {
    title,
    normalized_title,
    source: body.source || 'upload'
  },
  binary: {
    // Ensure we pass the file under a standard key 'file' for the S3 node
    file: binary[fileKey]
  }
}];

