const binary = $binary.data;  // your S3 binary key
const fileName = $json.file_path.split('/').pop(); // e.g., dangerous_liaisons.pdf
const ext = (fileName.split('.').pop() || '').toLowerCase();

let operation;
if (ext === 'pdf') {
  operation = 'pdf';
} else if (ext === 'epub') {
  operation = 'epub';
} else if (ext === 'txt') {
  operation = 'text';
} else {
  throw new Error(`Unsupported file type: ${ext}`);
}

// Pass this to Extract from File node
return [{
  json: {
    file_extension: ext,
    operation
  },
  binary: {
    data: binary
  }
}];

// In "Summaries cleaner" node
const summaries = $input.all()
  .sort((a, b) => a.json.chunkIndex - b.json.chunkIndex) // SORT BY INDEX
  .map(item => item.json.content.parts[0].text.trim());

return [{
  json: {
    summaries,
    combinedText: summaries.join('\n\n--- CHUNK BREAK ---\n\n'),
    totalChunks: summaries.length
  }
}];

const rawText = $input.first().json.content.parts[0].text;

// Aggressive cleanup
let cleanText = rawText
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .replace(/^[^[]*/, '') // Remove everything before first [
  .replace(/[^\]]*$/, '') // Remove everything after last ]
  .trim();

let scenes;
try {
  scenes = JSON.parse(cleanText);
} catch (e) {
  // Fallback: Try to extract JSON with regex
  const jsonMatch = cleanText.match(/\[[\s\S]*\]/);
  if (jsonMatch) {
    scenes = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error(`Failed to parse scenes: ${e.message}`);
  }
}

// Validation
if (!Array.isArray(scenes) || scenes.length < 3) {
  throw new Error(`Invalid scene count: ${scenes.length}. Need 3+`);
}

if (scenes.length > 30) {
  throw new Error(`Too many scenes: ${scenes.length}. Max 30.`);
}

// Validate structure
scenes.forEach((scene, i) => {
  if (!scene.narration_text || !scene.image_prompt) {
    throw new Error(`Scene ${i} missing required fields`);
  }
});

return scenes.map((scene, index) => ({
  json: {
    ...scene,
    sceneIndex: index,
    totalScenes: scenes.length
  }
}));

// items = [{ json: audio }, { json: image }]

const audioItem = items.find(i => i.json.is_audio === true);
const imageItem = items.find(i => i.json.resource_type === 'image');

if (!audioItem) {
  throw new Error('Audio asset not found in merged Cloudinary response');
}

if (!imageItem) {
  throw new Error('Image asset not found in merged Cloudinary response');
}

const audio = audioItem.json;
const image = imageItem.json;

return [
  {
    json: {
      audio: {
        public_id: audio.public_id,
        duration: audio.duration,
        url: audio.secure_url
      },
      image: {
        public_id: image.public_id,
        url: image.secure_url
      }
    }
  }
];

// Modern n8n syntax: process all incoming items
const items = $input.all();
const cloudName = "drdujsp3a";
const width = 1280;
const height = 720;

return items.map(item => {
  const audioPublicId = item.json.audio?.public_id;
  const imagePublicId = item.json.image?.public_id;

  if (!audioPublicId || !imagePublicId) {
    return { 
      json: { ...item.json, error: "Missing public_id for audio or image" } 
    };
  }

  // Cloudinary requires slashes in transformations to be replaced by colons
  const escapedImageId = imagePublicId.replace(/\//g, ':');
  const escapedAudioId = audioPublicId.replace(/\//g, ':');

  // Transformation: Layer the image, resize to fill 720p, apply
  const transformation = `l_${escapedImageId},w_${width},h_${height},c_fill/fl_layer_apply`;

  // Base URL: The audio file (must be uploaded as resource_type: video)
  const videoUrl = `https://res.cloudinary.com/${cloudName}/video/upload/${transformation}/${audioPublicId}.mp4`;

  return {
    json: {
      ...item.json,
      generated_video: {
        url: videoUrl,
        width,
        height,
        format: "mp4"
      }
    }
  };
});

let text = $input.first().json.data ||$input.first().json.text ;

if (!text || typeof text !== 'string') {
  throw new Error('No text to normalize');
}

// Only clean Gutenberg headers if they exist
if (/PROJECT GUTENBERG/i.test(text)) {
  const startMarkers = [
    /\*\*\* START OF (?:THE )?PROJECT GUTENBERG EBOOK .+? \*\*\*/i,
    /\*\*\*START OF THIS PROJECT GUTENBERG EBOOK .+?\*\*\*/i,
  ];

  for (const marker of startMarkers) {
    const match = text.match(marker);
    if (match) {
      text = text.slice(match.index + match[0].length);
      break;
    }
  }

  const endMarkers = [
    /\*\*\* END OF (?:THE )?PROJECT GUTENBERG EBOOK .+? \*\*\*/i,
    /\*\*\*END OF THIS PROJECT GUTENBERG EBOOK .+?\*\*\*/i,
  ];

  for (const marker of endMarkers) {
    const match = text.match(marker);
    if (match) {
      text = text.slice(0, match.index);
      break;
    }
  }
}

// Always normalize whitespace
text = text
  .trim()
  .replace(/\r\n/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .replace(/^\s+/gm, '');

return [{
  json: {
    cleanedText: text,
    textLength: text.length,
    source: /PROJECT GUTENBERG/i.test(text)
      ? 'gutendex'
      : 'other'
  }
}];

const bookText =$('Clean Text').first().json.cleanedText

if (!bookText || typeof bookText !== 'string') {
  throw new Error('No book text provided');
}

const MAX_TOKENS = 250000;
const AVG_CHAR_PER_TOKEN = 4;
const maxCharsPerChunk = MAX_TOKENS * AVG_CHAR_PER_TOKEN;

function chunkText(text, chunkSize) {
  const chunks = [];
  let start = 0;

  while (start < text.length) {
    let end = start + chunkSize;

    if (end < text.length) {
      const lastPeriod = text.lastIndexOf('.', end);
      if (lastPeriod > start) {
        end = lastPeriod + 1;
      }
    }

    chunks.push(text.slice(start, end).trim());
    start = end;
  }

  return chunks;
}

const chunks =
  bookText.length > maxCharsPerChunk
    ? chunkText(bookText, maxCharsPerChunk)
    : [bookText];

return chunks.map((chunk, index) => ({
  json: { chunkIndex: index, chunkText: chunk }
}));

const text =
  $input.first().json?.content?.parts?.[0]?.text;

if (!text) {
  throw new Error('No text found in Gemini response');
}

// Prepare safe versions
return [{
  json: {
    raw_text: text,
    text_json: JSON.stringify(text)
  }
}];
